def sha256_text(s: str) -> str:
    return hashlib.sha256(s.encode("utf-8")).hexdigest()


def now_ts() -> int:
    return int(time.time())


def read_text_file(path: str) -> str:
    with open(path, "rb") as f:
        data = f.read()
    try:
        return data.decode("utf-8")
    except UnicodeDecodeError:
        return data.decode("latin-1", errors="replace")


def iter_files(input_paths: List[str], exts: Optional[List[str]] = None) -> List[str]:
    files = []
    for p in input_paths:
        if os.path.isdir(p):
            for root, _, fnames in os.walk(p):
                for fn in fnames:
                    full = os.path.join(root, fn)
                    files.append(full)
        else:
            matches = glob.glob(p, recursive=True)
            if matches:
                files.extend(matches)
            else:
                files.append(p)
    out = []
    for f in files:
        if not os.path.isfile(f):
            continue
        if exts:
            ext = os.path.splitext(f)[1].lower()
            if ext not in exts:
                continue
        out.append(os.path.abspath(f))
    return sorted(set(out))


def chunk_text(text: str, chunk_size: int = 1200, chunk_overlap: int = 200) -> List[str]:
    text = text.replace("\r\n", "\n").replace("\r", "\n")
    if not text.strip():
        return []
    chunks = []
    start = 0
    n = len(text)
    while start < n:
        end = min(n, start + chunk_size)
        chunk = text[start:end].strip()
        if chunk:
            chunks.append(chunk)
        if end >= n:
            break
        start = max(0, end - chunk_overlap)
    return chunks


def cosine_sim(a: List[float], b: List[float]) -> float:
    if not a or not b or len(a) != len(b):
        return -1.0
    dot = 0.0
    na = 0.0
    nb = 0.0
    for x, y in zip(a, b):
        dot += x * y
        na += x * x
        nb += y * y
    if na <= 0 or nb <= 0:
        return -1.0
    return dot / (math.sqrt(na) * math.sqrt(nb))


class SQLiteVectorStore:
    def __init__(self, db_path: str):
        self.db_path = db_path
        self.conn = sqlite3.connect(self.db_path)
        self.conn.execute("PRAGMA journal_mode=WAL;")
        self.conn.execute("PRAGMA synchronous=NORMAL;")
        self._init_schema()

    def _init_schema(self):
        self.conn.execute(
            """
            CREATE TABLE IF NOT EXISTS documents (
                id TEXT PRIMARY KEY,
                source_path TEXT,
                source_hash TEXT,
                chunk_index INTEGER,
                content TEXT,
                content_hash TEXT,
                embedding_json TEXT,
                created_at INTEGER
            );
            """
        )
        self.conn.execute(
            "CREATE INDEX IF NOT EXISTS idx_documents_source_path ON documents(source_path);"
        )
        self.conn.execute(
            "CREATE INDEX IF NOT EXISTS idx_documents_source_hash ON documents(source_hash);"
        )
        self.conn.execute(
            "CREATE INDEX IF NOT EXISTS idx_documents_content_hash ON documents(content_hash);"
        )
        self.conn.commit()

    def upsert_chunk(
        self,
        doc_id: str,
        source_path: str,
        source_hash: str,
        chunk_index: int,
        content: str,
        embedding: List[float],
    ):
        content_hash = sha256_text(content)
        embedding_json = json.dumps(embedding, separators=(",", ":"))
        self.conn.execute(
            """
            INSERT INTO documents (id, source_path, source_hash, chunk_index, content, content_hash, embedding_json, created_at)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?)
            ON CONFLICT(id) DO UPDATE SET
                source_path=excluded.source_path,
                source_hash=excluded.source_hash,
                chunk_index=excluded.chunk_index,
                content=excluded.content,
                content_hash=excluded.content_hash,
                embedding_json=excluded.embedding_json
            ;
            """,
            (doc_id, source_path, source_hash, chunk_index, content, content_hash, embedding_json, now_ts()),
        )

    def delete_by_source_path(self, source_path: str):
        self.conn.execute("DELETE FROM documents WHERE source_path = ?;", (source_path,))

    def list_sources(self) -> List[Tuple[str, int]]:
        cur = self.conn.execute(
            "SELECT source_path, COUNT(*) FROM documents GROUP BY source_path ORDER BY source_path;"
        )
        return list(cur.fetchall())

    def count(self) -> int:
        cur = self.conn.execute("SELECT COUNT(*) FROM documents;")
        return int(cur.fetchone()[0])

    def fetch_all(self) -> List[Dict[str, Any]]:
        cur = self.conn.execute(
            "SELECT id, source_path, source_hash, chunk_index, content, embedding_json FROM documents;"
        )
        rows = cur.fetchall()
        out = []
        for r in rows:
            out.append(
                {
                    "id": r[0],
                    "source_path": r[1],
                    "source_hash": r[2],
                    "chunk_index": r[3],
                    "content": r[4],
                    "embedding": json.loads(r[5]),
                }
            )
        return out

    def search(self, query_embedding: List[float], top_k: int = 8) -> List[Dict[str, Any]]:
        cur = self.conn.execute(
            "SELECT id, source_path, chunk_index, content, embedding_json FROM documents;"
        )
        scored = []
        for doc_id, source_path, chunk_index, content, emb_json in cur.fetchall():
            emb = json.loads(emb_json)
            score = cosine_sim(query_embedding, emb)
            scored.append(
                {
                    "id": doc_id,
                    "source_path": source_path,
                    "chunk_index": chunk_index,
                    "content": content,
                    "score": float(score),
                }
            )
        scored.sort(key=lambda x: x["score"], reverse=True)
        return scored[:top_k]

    def close(self):
        try:
            self.conn.commit()
        finally:
            self.conn.close()


class OpenAIEmbedder:
    def __init__(self, api_key: Optional[str] = None, base_url: Optional[str] = None, model: str = "text-embedding-3-large"):
        if OpenAI is None:
            raise RuntimeError("openai package not installed. Run: pip install openai")
        self.client = OpenAI(api_key=api_key or os.environ.get("OPENAI_API_KEY"), base_url=base_url or os.environ.get("OPENAI_BASE_URL"))
        self.model = model

    def embed_texts(self, texts: List[str]) -> List[List[float]]:
        if not texts:
            return []
        resp = self.client.embeddings.create(model=self.model, input=texts)
        return [d.embedding for d in resp.data]

    def embed_text(self, text: str) -> List[float]:
        return self.embed_texts([text])[0]


class OpenAIChatLLM:
    def __init__(self, api_key: Optional[str] = None, base_url: Optional[str] = None, model: str = "gpt-4.1-mini"):
        if OpenAI is None:
            raise RuntimeError("openai package not installed. Run: pip install openai")
        self.client = OpenAI(api_key=api_key or os.environ.get("OPENAI_API_KEY"), base_url=base_url or os.environ.get("OPENAI_BASE_URL"))
        self.model = model

    def generate(self, system_prompt: str, user_prompt: str, temperature: float = 0.2) -> str:
        resp = self.client.chat.completions.create(
            model=self.model,
            temperature=temperature,
            messages=[
                {"role": "system", "content": system_prompt},
                {"role": "user", "content": user_prompt},
            ],
        )
        return resp.choices[0].message.content


def build_rag_prompt(query: str, retrieved: List[Dict[str, Any]]) -> str:
    parts = []
    parts.append("USER QUESTION:\n" + query.strip())
    parts.append("\nRETRIEVED CONTEXT DOCUMENTS (use all of them; cite by [docN]):\n")
    for i, d in enumerate(retrieved, start=1):
        header = f"[doc{i}] source={d.get('source_path')} chunk={d.get('chunk_index')} score={d.get('score'):.4f}"
        content = d.get("content", "").strip()
        parts.append(header + "\n" + content + "\n")
    parts.append(
        "INSTRUCTIONS:\n"
        "- Answer using only the retrieved context documents.\n"
        "- If the answer is not present in the context, say: \"I don't know based on the provided documents.\" \n"
        "- Provide concise, helpful steps or bullet points when appropriate.\n"
        "- Include citations like [doc2] after the relevant sentences.\n"
    )
    return "\n".join(parts)


DEFAULT_SYSTEM_PROMPT = (
    "You are an internal knowledge base assistant. "
    "Follow the user's instructions if they do not conflict with policy. "
    "Use only the provided retrieved documents as your source of truth, and cite them."
)


def ingest(
    db_path: str,
    input_paths: List[str],
    embed_model: str,
    chunk_size: int,
    chunk_overlap: int,
    exts: Optional[List[str]] = None,
    api_key: Optional[str] = None,
    base_url: Optional[str] = None,
    batch_size: int = 64,
):
    store = SQLiteVectorStore(db_path)
    embedder = OpenAIEmbedder(api_key=api_key, base_url=base_url, model=embed_model)

    files = iter_files(input_paths, exts=exts)
    if not files:
        print("No files found.", file=sys.stderr)
        store.close()
        return

    for path in files:
        text = read_text_file(path)
        source_hash = sha256_text(text)
        chunks = chunk_text(text, chunk_size=chunk_size, chunk_overlap=chunk_overlap)

        store.delete_by_source_path(os.path.abspath(path))

        doc_ids = []
        contents = []
        for idx, ch in enumerate(chunks):
            doc_id = str(uuid.uuid5(uuid.NAMESPACE_URL, f"{os.path.abspath(path)}::{source_hash}::{idx}"))
            doc_ids.append((doc_id, idx, ch))
            contents.append(ch)

        embeddings: List[List[float]] = []
        for i in range(0, len(contents), batch_size):
            batch = contents[i : i + batch_size]
            embeddings.extend(embedder.embed_texts(batch))

        store.conn.execute("BEGIN;")
        try:
            for (doc_id, idx, ch), emb in zip(doc_ids, embeddings):
                store.upsert_chunk(
                    doc_id=doc_id,
                    source_path=os.path.abspath(path),
                    source_hash=source_hash,
                    chunk_index=idx,
                    content=ch,
                    embedding=emb,
                )
            store.conn.commit()
        except Exception:
            store.conn.rollback()
            raise

        print(f"Ingested {len(chunks)} chunks from: {path}")

    print(f"Vector DB ready: {db_path} (total chunks: {store.count()})")
    store.close()


def query(
    db_path: str,
    user_query: str,
    top_k: int,
    embed_model: str,
    chat_model: str,
    system_prompt: str,
    api_key: Optional[str] = None,
    base_url: Optional[str] = None,
    temperature: float = 0.2,
    show_retrieved: bool = False,
):
    store = SQLiteVectorStore(db_path)
    embedder = OpenAIEmbedder(api_key=api_key, base_url=base_url, model=embed_model)
    llm = OpenAIChatLLM(api_key=api_key, base_url=base_url, model=chat_model)

    q_emb = embedder.embed_text(user_query)
    retrieved = store.search(q_emb, top_k=top_k)

    if show_retrieved:
        print(json.dumps(retrieved, indent=2))

    rag_prompt = build_rag_prompt(user_query, retrieved)
    answer = llm.generate(system_prompt=system_prompt, user_prompt=rag_prompt, temperature=temperature)
    print(answer)

    store.close()


def repl(
    db_path: str,
    top_k: int,
    embed_model: str,
    chat_model: str,
    system_prompt: str,
    api_key: Optional[str] = None,
    base_url: Optional[str] = None,
    temperature: float = 0.2,
):
    store = SQLiteVectorStore(db_path)
    embedder = OpenAIEmbedder(api_key=api_key, base_url=base_url, model=embed_model)
    llm = OpenAIChatLLM(api_key=api_key, base_url=base_url, model=chat_model)

    print("RAG chatbot REPL. Type /exit to quit, /sources to list ingested sources.")
    while True:
        try:
            user_query = input("\n> ").strip()
        except (EOFError, KeyboardInterrupt):
            break
        if not user_query:
            continue
        if user_query.lower() in ("/exit", "exit", "quit", "/quit"):
            break
        if user_query.lower() in ("/sources", "sources"):
            for src, cnt in store.list_sources():
                print(f"{src} ({cnt} chunks)")
            continue

        q_emb = embedder.embed_text(user_query)
        retrieved = store.search(q_emb, top_k=top_k)
        rag_prompt = build_rag_prompt(user_query, retrieved)
        answer = llm.generate(system_prompt=system_prompt, user_prompt=rag_prompt, temperature=temperature)
        print("\n" + answer)

    store.close()


def parse_args():
    p = argparse.ArgumentParser(description="Simple Python RAG system (SQLite vector store + OpenAI embeddings + chat).")
    p.add_argument("--db", default="rag_vectors.sqlite3", help="Path to SQLite DB file.")
    p.add_argument("--api-key", default=None, help="API key (or set OPENAI_API_KEY).")
    p.add_argument("--base-url", default=None, help="Base URL (or set OPENAI_BASE_URL).")

    sub = p.add_subparsers(dest="cmd", required=True)

    pi = sub.add_parser("ingest", help="Ingest documents into vector DB.")
    pi.add_argument("paths", nargs="+", help="Files/dirs/globs to ingest.")
    pi.add_argument("--exts", default=".txt,.md,.rst,.log,.csv,.json,.yaml,.yml", help="Comma-separated allowed extensions.")
    pi.add_argument("--chunk-size", type=int, default=1200)
    pi.add_argument("--chunk-overlap", type=int, default=200)
    pi.add_argument("--embed-model", default="text-embedding-3-large")
    pi.add_argument("--batch-size", type=int, default=64)

    pq = sub.add_parser("query", help="Ask a single question.")
    pq.add_argument("q", help="User query.")
    pq.add_argument("--top-k", type=int, default=8)
    pq.add_argument("--embed-model", default="text-embedding-3-large")
    pq.add_argument("--chat-model", default="gpt-4.1-mini")
    pq.add_argument("--system-prompt", default=DEFAULT_SYSTEM_PROMPT)
    pq.add_argument("--temperature", type=float, default=0.2)
    pq.add_argument("--show-retrieved", action="store_true")

    pr = sub.add_parser("repl", help="Interactive chatbot.")
    pr.add_argument("--top-k", type=int, default=8)
    pr.add_argument("--embed-model", default="text-embedding-3-large")
    pr.add_argument("--chat-model", default="gpt-4.1-mini")
    pr.add_argument("--system-prompt", default=DEFAULT_SYSTEM_PROMPT)
    pr.add_argument("--temperature", type=float, default=0.2)

    return p.parse_args()


def main():
    args = parse_args()
    exts = None
    if args.cmd == "ingest":
        exts = [e.strip().lower() for e in args.exts.split(",") if e.strip()]
        ingest(
            db_path=args.db,
            input_paths=args.paths,
            embed_model=args.embed_model,
            chunk_size=args.chunk_size,
            chunk_overlap=args.chunk_overlap,
            exts=exts,
            api_key=args.api_key,
            base_url=args.base_url,
            batch_size=args.batch_size,
        )
    elif args.cmd == "query":
        query(
            db_path=args.db,
            user_query=args.q,
            top_k=args.top_k,
            embed_model=args.embed_model,
            chat_model=args.chat_model,
            system_prompt=args.system_prompt,
            api_key=args.api_key,
            base_url=args.base_url,
            temperature=args.temperature,
            show_retrieved=args.show_retrieved,
        )
    elif args.cmd == "repl":
        repl(
            db_path=args.db,
            top_k=args.top_k,
            embed_model=args.embed_model,
            chat_model=args.chat_model,
            system_prompt=args.system_prompt,
            api_key=args.api_key,
            base_url=args.base_url,
            temperature=args.temperature,
        )
    else:
        raise SystemExit("Unknown command")


if __name__ == "__main__":
    main()